SELECT TOP 1 MAX(oMonetaryAmount.[HASAMOUNT]) AS AggResult1 FROM [FIBEN].[LISTEDSECURITY] oListedSecurity INNER JOIN [FIBEN].[MONETARYAMOUNT] oMonetaryAmount ON oListedSecurity.[HASLASTTRADEDVALUE]=oMonetaryAmount.[MONETARYAMOUNTID] WHERE oMonetaryAmount.[HASAMOUNT] u003c 100 AND oMonetaryAmount.[HASAMOUNT] u003c 100.0 ORDER BY AggResult1 DESC